  ('disabled-7c4986e7-moex-00045', 'disabled-7c4986e7', 'disabled-7c4986e7-moex-114-6948958a', 'sub-disabled-7c4986e7-01', NULL, 'single_choice', '假設A國的M1A供給額為800，其中通貨淨額為200、活期存款為600。 同時 A 國法定存款準備金總額為 200，沒有任何超額準備。若民眾將 50 萬元通貨存入銀行的活期存款帳戶，下列敘述何者正確？', '["貨幣供給額增加", "M1A乘數減少", "貨幣基數減少", "法定存款準備金總額不變"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:58+00:00", "source_pdf_sha1": "b8525077d2fd", "answer_pdf_sha1": "4fb29f00a092", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "407", "s": "0806", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學概要", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 45, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "金融保險"}'::jsonb, NULL)
